 7→alter table public.merchants add column if not exists geog geography(Point, 4326);
 8→
 9→-- Auto-update geography column from lat/lng
10→create or replace function update_merchant_geog()
11→returns trigger as $$
12→begin
13→  if new.latitude is not null and new.longitude is not null then
14→    new.geog = st_point(new.longitude, new.latitude)::geography;
15→  end if;
16→  return new;
17→end;
18→$$ language plpgsql;
19→
20→create trigger merchant_geog_trigger before insert or update on merchants
21→  for each row execute function update_merchant_geog();
22→
23→-- Spatial index for proximity queries
24→create index idx_merchants_geog on merchants using gist(geog);
25→
26→-- RPC function to find merchants within a given radius
27→create or replace function find_nearby_merchants(user_lat double precision, user_lng double precision, radius_meters int)
28→returns table(id uuid, name text, latitude double precision, longitude double precision, distance double precision) as $$
29→  select m.id, m.name, m.latitude, m.longitude,
30→    st_distance(m.geog, st_point(user_lng, user_lat)::geography) as distance
31→  from merchants m
32→  where m.geog is not null
33→    and st_dwithin(m.geog, st_point(user_lng, user_lat)::geography, radius_meters)
34→  order by distance;
35→$$ language sql stable;
