  1→import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
  2→
  3→const corsHeaders = {
  4→  'Access-Control-Allow-Origin': '*',
  5→  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  6→};
  7→
  8→Deno.serve(async (req) => {
  9→  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });
 10→
 11→  try {
 12→    const supabase = createClient(
 13→      Deno.env.get('SUPABASE_URL')!,
 14→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
 15→    );
 16→
 17→    const now = new Date();
 18→    const oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();
 19→    const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000).toISOString();
 20→    let totalSent = 0;
 21→
 22→    // 1. INACTIVITY REMINDERS
 23→    // Find customer_cards where last_activity > 14 days ago
 24→    const { data: inactiveCards } = await supabase
 25→      .from('customer_cards')
 26→      .select('id, customer_id, customers(push_token)')
 27→      .lt('last_activity', fourteenDaysAgo);
 28→
 29→    for (const card of inactiveCards ?? []) {
 30→      const token = (card as any).customers?.push_token;
 31→      if (!token) continue;
 32→
 33→      // Dedup: check if an inactivity notification (expiration_warning with specific title) was already sent in last 24h
 34→      const { count } = await supabase
 35→        .from('notifications')
 36→        .select('id', { count: 'exact', head: true })
 37→        .eq('customer_id', card.customer_id)
 38→        .eq('type', 'expiration_warning')
 39→        .eq('title', 'We miss you!')
 40→        .gte('sent_at', oneDayAgo);
 41→
 42→      if ((count ?? 0) > 0) continue;
 43→
 44→      await fetch('https://exp.host/--/api/v2/push/send', {
 45→        method: 'POST',
 46→        headers: { 'Content-Type': 'application/json' },
 47→        body: JSON.stringify({
 48→          to: token,
 49→          title: 'We miss you!',
 50→          body: 'Come back and check your loyalty rewards!',
 51→        }),
 52→      });
 53→
 54→      await supabase.from('notifications').insert({
 55→        customer_id: card.customer_id,
 56→        title: 'We miss you!',
 57→        body: 'Come back and check your loyalty rewards!',
 58→        type: 'expiration_warning', // closest available type for inactivity
 59→        sent_at: now.toISOString(),
 60→      });
 61→      totalSent++;
 62→    }
 63→
 64→    // 2. EXPIRATION WARNING
 65→    // Find customer_cards whose points/stamps will expire within 7 days
 66→    const { data: expiringCards } = await supabase
 67→      .from('customer_cards')
 68→      .select('id, customer_id, created_at, customers(push_token), loyalty_programs(expiration_days, name)')
 69→      .not('loyalty_programs.expiration_days', 'is', null);
 70→
 71→    for (const card of expiringCards ?? []) {
 72→      const program = (card as any).loyalty_programs;
 73→      if (!program?.expiration_days) continue;
 74→      const token = (card as any).customers?.push_token;
 75→      if (!token) continue;
 76→
 77→      const expiresAt = new Date(new Date(card.created_at).getTime() + program.expiration_days * 24 * 60 * 60 * 1000);
 78→      const daysUntilExpiry = (expiresAt.getTime() - now.getTime()) / (24 * 60 * 60 * 1000);
 79→      if (daysUntilExpiry > 7 || daysUntilExpiry < 0) continue;
 80→
 81→      // Dedup: check if an expiration warning was already sent in last 24h
 82→      const { count } = await supabase
 83→        .from('notifications')
 84→        .select('id', { count: 'exact', head: true })
 85→        .eq('customer_id', card.customer_id)
 86→        .eq('type', 'expiration_warning')
 87→        .eq('title', 'Points expiring soon!')
 88→        .gte('sent_at', oneDayAgo);
 89→      if ((count ?? 0) > 0) continue;
 90→
 91→      await fetch('https://exp.host/--/api/v2/push/send', {
 92→        method: 'POST',
 93→        headers: { 'Content-Type': 'application/json' },
 94→        body: JSON.stringify({
 95→          to: token,
 96→          title: 'Points expiring soon!',
 97→          body: `Your rewards at ${program.name} expire in ${Math.ceil(daysUntilExpiry)} days!`,
 98→        }),
 99→      });
100→
101→      await supabase.from('notifications').insert({
102→        customer_id: card.customer_id,
103→        title: 'Points expiring soon!',
104→        body: `Your rewards at ${program.name} expire in ${Math.ceil(daysUntilExpiry)} days!`,
105→        type: 'expiration_warning',
106→        sent_at: now.toISOString(),
107→      });
108→      totalSent++;
109→    }
110→
111→    // 3. REWARD AVAILABLE
112→    // Find customer_cards where stamps >= stamp_goal or points >= any reward's points_cost
113→    const { data: readyCards } = await supabase
114→      .from('customer_cards')
115→      .select('id, customer_id, current_stamps, current_points, customers(push_token), loyalty_programs(type, stamp_goal, name, id)');
116→
117→    for (const card of readyCards ?? []) {
118→      const program = (card as any).loyalty_programs;
119→      const token = (card as any).customers?.push_token;
120→      if (!token || !program) continue;
121→
122→      let eligible = false;
123→      if (program.type === 'stamp' && card.current_stamps >= program.stamp_goal) {
124→        eligible = true;
125→      } else if (program.type === 'points') {
126→        const { data: rewards } = await supabase
127→          .from('rewards')
128→          .select('points_cost')
129→          .eq('program_id', program.id)
130→          .lte('points_cost', card.current_points)
131→          .limit(1);
132→        if (rewards && rewards.length > 0) eligible = true;
133→      }
134→
135→      if (!eligible) continue;
136→
137→      // Dedup: check if a reward_available notification was already sent in last 24h
138→      const { count } = await supabase
139→        .from('notifications')
140→        .select('id', { count: 'exact', head: true })
141→        .eq('customer_id', card.customer_id)
142→        .eq('type', 'reward_available')
143→        .gte('sent_at', oneDayAgo);
144→      if ((count ?? 0) > 0) continue;
145→
146→      await fetch('https://exp.host/--/api/v2/push/send', {
147→        method: 'POST',
148→        headers: { 'Content-Type': 'application/json' },
149→        body: JSON.stringify({
150→          to: token,
151→          title: 'Reward available!',
152→          body: `You have enough to claim a reward at ${program.name}!`,
153→        }),
154→      });
155→
156→      await supabase.from('notifications').insert({
157→        customer_id: card.customer_id,
158→        title: 'Reward available!',
159→        body: `You have enough to claim a reward at ${program.name}!`,
160→        type: 'reward_available',
161→        sent_at: now.toISOString(),
162→      });
163→      totalSent++;
164→    }
165→
166→    return new Response(JSON.stringify({ sent: totalSent }), {
167→      status: 200,
168→      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
169→    });
170→  } catch (err) {
171→    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
172→  }
173→});
