  3→const corsHeaders = {
  4→  'Access-Control-Allow-Origin': '*',
  5→  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  6→};
  7→
  8→Deno.serve(async (req) => {
  9→  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });
 10→
 11→  try {
 12→    const supabase = createClient(
 13→      Deno.env.get('SUPABASE_URL')!,
 14→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
 15→    );
 16→
 17→    const { referral_code, new_customer_id } = await req.json();
 18→    if (!referral_code || !new_customer_id) {
 19→      return new Response(
 20→        JSON.stringify({ error: 'Missing referral_code or new_customer_id' }),
 21→        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
 22→      );
 23→    }
 24→
 25→    // Find the referral
 26→    const { data: referral } = await supabase
 27→      .from('referrals')
 28→      .select('*')
 29→      .eq('referral_code', referral_code)
 30→      .is('referred_id', null)
 31→      .single();
 32→
 33→    if (!referral) {
 34→      return new Response(
 35→        JSON.stringify({ error: 'Invalid or already used referral code' }),
 36→        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
 37→      );
 38→    }
 39→
 40→    // Prevent self-referral
 41→    if (referral.referrer_id === new_customer_id) {
 42→      return new Response(
 43→        JSON.stringify({ error: 'Cannot use your own referral code' }),
 44→        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
 45→      );
 46→    }
 47→
 48→    // Update referral with referred user
 49→    await supabase
 50→      .from('referrals')
 51→      .update({
 52→        referred_id: new_customer_id,
 53→        status: 'completed',
 54→        reward_given: true,
 55→      })
 56→      .eq('id', referral.id);
 57→
 58→    // Award 50 bonus points to both referrer and referred user on their first card
 59→    const bonusPoints = 50;
 60→
 61→    // Get first card for referrer
 62→    const { data: referrerCard } = await supabase
 63→      .from('customer_cards')
 64→      .select('id, current_points')
 65→      .eq('customer_id', referral.referrer_id)
 66→      .order('created_at', { ascending: true })
 67→      .limit(1)
 68→      .single();
 69→
 70→    if (referrerCard) {
 71→      await supabase
 72→        .from('customer_cards')
 73→        .update({ current_points: referrerCard.current_points + bonusPoints })
 74→        .eq('id', referrerCard.id);
 75→
 76→      await supabase.from('transactions').insert({
 77→        card_id: referrerCard.id,
 78→        type: 'points_add',
 79→        value: bonusPoints,
 80→        validated_by: 'manual',
 81→      });
 82→    }
 83→
 84→    // Get first card for referred user
 85→    const { data: referredCard } = await supabase
 86→      .from('customer_cards')
 87→      .select('id, current_points')
 88→      .eq('customer_id', new_customer_id)
 89→      .order('created_at', { ascending: true })
 90→      .limit(1)
 91→      .single();
 92→
 93→    if (referredCard) {
 94→      await supabase
 95→        .from('customer_cards')
 96→        .update({ current_points: referredCard.current_points + bonusPoints })
 97→        .eq('id', referredCard.id);
 98→
 99→      await supabase.from('transactions').insert({
100→        card_id: referredCard.id,
101→        type: 'points_add',
102→        value: bonusPoints,
103→        validated_by: 'manual',
104→      });
105→    }
106→
107→    return new Response(
108→      JSON.stringify({ success: true, bonus_points: bonusPoints }),
109→      {
110→        status: 200,
111→        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
112→      }
113→    );
114→  } catch (err) {
115→    return new Response(
116→      JSON.stringify({ error: (err as Error).message }),
117→      { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
118→    );
119→  }
120→});
