  1→import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
  2→
  3→const corsHeaders = {
  4→  'Access-Control-Allow-Origin': '*',
  5→  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  6→};
  7→
  8→Deno.serve(async (req) => {
  9→  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });
 10→
 11→  try {
 12→    const supabase = createClient(
 13→      Deno.env.get('SUPABASE_URL')!,
 14→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
 15→    );
 16→
 17→    const authHeader = req.headers.get('Authorization');
 18→    if (!authHeader) {
 19→      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
 20→        status: 401,
 21→        headers: corsHeaders,
 22→      });
 23→    }
 24→
 25→    // Get the authenticated user
 26→    const { data: { user } } = await supabase.auth.getUser(
 27→      authHeader.replace('Bearer ', '')
 28→    );
 29→    if (!user) {
 30→      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
 31→        status: 401,
 32→        headers: corsHeaders,
 33→      });
 34→    }
 35→
 36→    const { lat, lng } = await req.json();
 37→    if (!lat || !lng) {
 38→      return new Response(JSON.stringify({ error: 'Missing lat/lng' }), {
 39→        status: 400,
 40→        headers: corsHeaders,
 41→      });
 42→    }
 43→
 44→    // Find merchants within 500m
 45→    const { data: nearbyMerchants } = await supabase.rpc('find_nearby_merchants', {
 46→      user_lat: lat,
 47→      user_lng: lng,
 48→      radius_meters: 500,
 49→    });
 50→
 51→    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
 52→    let sent = 0;
 53→
 54→    for (const merchant of nearbyMerchants ?? []) {
 55→      // Check if customer has a card with this merchant
 56→      const { data: cards } = await supabase
 57→        .from('customer_cards')
 58→        .select('id, loyalty_programs!inner(merchant_id)')
 59→        .eq('customer_id', user.id)
 60→        .eq('loyalty_programs.merchant_id', merchant.id);
 61→
 62→      if (!cards || cards.length === 0) continue;
 63→
 64→      // Dedup: check if proximity notification sent in last 24h
 65→      const { count } = await supabase
 66→        .from('notifications')
 67→        .select('id', { count: 'exact', head: true })
 68→        .eq('customer_id', user.id)
 69→        .eq('type', 'proximity')
 70→        .gte('sent_at', oneDayAgo);
 71→
 72→      if ((count ?? 0) > 0) continue;
 73→
 74→      // Get customer push token
 75→      const { data: customer } = await supabase
 76→        .from('customers')
 77→        .select('push_token')
 78→        .eq('id', user.id)
 79→        .single();
 80→
 81→      if (!customer?.push_token) continue;
 82→
 83→      await fetch('https://exp.host/--/api/v2/push/send', {
 84→        method: 'POST',
 85→        headers: { 'Content-Type': 'application/json' },
 86→        body: JSON.stringify({
 87→          to: customer.push_token,
 88→          title: `You're near ${merchant.name}!`,
 89→          body: 'Check your rewards and offers!',
 90→          data: { type: 'proximity', merchant_id: merchant.id },
 91→        }),
 92→      });
 93→
 94→      await supabase.from('notifications').insert({
 95→        customer_id: user.id,
 96→        title: `You're near ${merchant.name}!`,
 97→        body: 'Check your rewards and offers!',
 98→        type: 'proximity',
 99→        sent_at: new Date().toISOString(),
100→      });
101→      sent++;
102→    }
103→
104→    return new Response(JSON.stringify({ sent }), {
105→      status: 200,
106→      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
107→    });
108→  } catch (err) {
109→    return new Response(JSON.stringify({ error: (err as Error).message }), {
110→      status: 500,
111→      headers: corsHeaders,
112→    });
113→  }
114→});
