  1→import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
  2→
  3→const corsHeaders = {
  4→  'Access-Control-Allow-Origin': '*',
  5→  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  6→};
  7→
  8→/**
  9→ * Shuffle an array in-place using Fisher-Yates and return it.
 10→ */
 11→function shuffle<T>(arr: T[]): T[] {
 12→  for (let i = arr.length - 1; i > 0; i--) {
 13→    const j = Math.floor(Math.random() * (i + 1));
 14→    [arr[i], arr[j]] = [arr[j], arr[i]];
 15→  }
 16→  return arr;
 17→}
 18→
 19→Deno.serve(async (req) => {
 20→  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });
 21→
 22→  try {
 23→    const supabase = createClient(
 24→      Deno.env.get('SUPABASE_URL')!,
 25→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
 26→    );
 27→
 28→    const { campaign_id, ab_test, variant_b_id } = await req.json();
 29→    if (!campaign_id) return new Response(JSON.stringify({ error: 'Missing campaign_id' }), { status: 400, headers: corsHeaders });
 30→
 31→    const { data: campaign } = await supabase.from('campaigns').select('*').eq('id', campaign_id).single();
 32→    if (!campaign) return new Response(JSON.stringify({ error: 'Campaign not found' }), { status: 404, headers: corsHeaders });
 33→
 34→    // Fetch filtered audience (shared for both modes)
 35→    const { data: cards } = await supabase
 36→      .from('customer_cards')
 37→      .select('customer_id, created_at, last_activity, tier, customers(push_token), loyalty_programs!inner(merchant_id)')
 38→      .eq('loyalty_programs.merchant_id', campaign.merchant_id);
 39→
 40→    const now = new Date();
 41→    const filteredCards = (cards ?? []).filter((c: any) => {
 42→      switch (campaign.target_segment) {
 43→        case 'new': {
 44→          if (!c.created_at) return false;
 45→          const createdAt = new Date(c.created_at);
 46→          const daysSinceCreation = (now.getTime() - createdAt.getTime()) / (1000 * 60 * 60 * 24);
 47→          return daysSinceCreation <= 30;
 48→        }
 49→        case 'inactive': {
 50→          if (!c.last_activity) return true;
 51→          const lastActivity = new Date(c.last_activity);
 52→          const daysSinceActivity = (now.getTime() - lastActivity.getTime()) / (1000 * 60 * 60 * 24);
 53→          return daysSinceActivity > 14;
 54→        }
 55→        case 'vip': {
 56→          const tier = (c.tier ?? '').toLowerCase();
 57→          return tier === 'gold' || tier === 'vip';
 58→        }
 59→        case 'all':
 60→        default:
 61→          return true;
 62→      }
 63→    });
 64→
 65→    // ---------- A/B Test path ----------
 66→    if (ab_test && variant_b_id) {
 67→      const { data: campaignB } = await supabase.from('campaigns').select('*').eq('id', variant_b_id).single();
 68→      if (!campaignB) return new Response(JSON.stringify({ error: 'Variant B campaign not found' }), { status: 404, headers: corsHeaders });
 69→
 70→      // Shuffle and split audience 50/50
 71→      shuffle(filteredCards);
 72→      const midpoint = Math.ceil(filteredCards.length / 2);
 73→      const groupA = filteredCards.slice(0, midpoint);
 74→      const groupB = filteredCards.slice(midpoint);
 75→
 76→      const tokensA = groupA.map((c: any) => c.customers?.push_token).filter(Boolean) as string[];
 77→      const tokensB = groupB.map((c: any) => c.customers?.push_token).filter(Boolean) as string[];
 78→
 79→      // Send variant A
 80→      if (tokensA.length) {
 81→        const messagesA = tokensA.map((token) => ({
 82→          to: token,
 83→          title: campaign.title,
 84→          body: campaign.body,
 85→          data: { campaign_id: campaign.id, type: 'campaign' },
 86→        }));
 87→        await fetch('https://exp.host/--/api/v2/push/send', {
 88→          method: 'POST',
 89→          headers: { 'Content-Type': 'application/json' },
 90→          body: JSON.stringify(messagesA),
 91→        });
 92→      }
 93→
 94→      // Send variant B
 95→      if (tokensB.length) {
 96→        const messagesB = tokensB.map((token) => ({
 97→          to: token,
 98→          title: campaignB.title,
 99→          body: campaignB.body,
100→          data: { campaign_id: campaignB.id, type: 'campaign' },
101→        }));
102→        await fetch('https://exp.host/--/api/v2/push/send', {
103→          method: 'POST',
104→          headers: { 'Content-Type': 'application/json' },
105→          body: JSON.stringify(messagesB),
106→        });
107→      }
108→
109→      // Record notifications for variant A
110→      const notificationsA = groupA.map((c: any) => ({
111→        customer_id: c.customer_id,
112→        campaign_id: campaign.id,
113→        title: campaign.title,
114→        body: campaign.body,
115→        type: 'campaign' as const,
116→      }));
117→
118→      // Record notifications for variant B
119→      const notificationsB = groupB.map((c: any) => ({
120→        customer_id: c.customer_id,
121→        campaign_id: campaignB.id,
122→        title: campaignB.title,
123→        body: campaignB.body,
124→        type: 'campaign' as const,
125→      }));
126→
127→      const allNotifications = [...notificationsA, ...notificationsB];
128→      if (allNotifications.length) {
129→        await supabase.from('notifications').insert(allNotifications);
130→      }
131→
132→      // Mark both campaigns as sent
133→      const sentAt = new Date().toISOString();
134→      await supabase.from('campaigns').update({ status: 'sent', sent_at: sentAt }).eq('id', campaign.id);
135→      await supabase.from('campaigns').update({ status: 'sent', sent_at: sentAt }).eq('id', campaignB.id);
136→
137→      return new Response(
138→        JSON.stringify({ sent: tokensA.length + tokensB.length, variant_a: tokensA.length, variant_b: tokensB.length }),
139→        { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
140→      );
141→    }
142→
143→    // ---------- Standard (non-A/B) path ----------
144→    const tokens = filteredCards
145→      .map((c: any) => c.customers?.push_token)
146→      .filter(Boolean) as string[];
147→
148→    if (!tokens.length) {
149→      return new Response(JSON.stringify({ sent: 0 }), { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
150→    }
151→
152→    const messages = tokens.map((token) => ({
153→      to: token,
154→      title: campaign.title,
155→      body: campaign.body,
156→      data: { campaign_id: campaign.id, type: 'campaign' },
157→    }));
158→
159→    await fetch('https://exp.host/--/api/v2/push/send', {
160→      method: 'POST',
161→      headers: { 'Content-Type': 'application/json' },
162→      body: JSON.stringify(messages),
163→    });
164→
165→    const notifications = filteredCards.map((c: any) => ({
166→      customer_id: c.customer_id,
167→      campaign_id: campaign.id,
168→      title: campaign.title,
169→      body: campaign.body,
170→      type: 'campaign' as const,
171→    }));
172→
173→    if (notifications.length) {
174→      await supabase.from('notifications').insert(notifications);
175→    }
176→
177→    await supabase.from('campaigns').update({
178→      status: 'sent',
179→      sent_at: new Date().toISOString(),
180→    }).eq('id', campaign.id);
181→
182→    return new Response(JSON.stringify({ sent: tokens.length }), {
183→      status: 200,
184→      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
185→    });
186→
187→  } catch (err) {
188→    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
189→  }
190→});
