 1→import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
 2→
 3→const corsHeaders = {
 4→  'Access-Control-Allow-Origin': '*',
 5→  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
 6→};
 7→
 8→Deno.serve(async (req) => {
 9→  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });
10→
11→  try {
12→    const supabase = createClient(
13→      Deno.env.get('SUPABASE_URL')!,
14→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
15→    );
16→
17→    const ninetyDaysAgo = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString();
18→    let updated = 0;
19→
20→    // Get all customer cards with their programs
21→    const { data: cards } = await supabase
22→      .from('customer_cards')
23→      .select('id, customer_id, current_points, tier, program_id, customers(push_token)');
24→
25→    for (const card of cards ?? []) {
26→      // Count transactions in last 90 days
27→      const { count: txCount } = await supabase
28→        .from('transactions')
29→        .select('id', { count: 'exact', head: true })
30→        .eq('card_id', card.id)
31→        .gte('created_at', ninetyDaysAgo);
32→
33→      // Get tier rules for this program, ordered by min_transactions desc (highest tier first)
34→      const { data: rules } = await supabase
35→        .from('tier_rules')
36→        .select('*')
37→        .eq('program_id', card.program_id)
38→        .order('min_transactions', { ascending: false });
39→
40→      if (!rules || rules.length === 0) continue;
41→
42→      // Determine highest qualifying tier
43→      let newTier = 'bronze';
44→      for (const rule of rules) {
45→        if ((txCount ?? 0) >= rule.min_transactions && card.current_points >= (rule.min_points ?? 0)) {
46→          newTier = rule.tier;
47→          break; // rules sorted desc, first match is highest tier
48→        }
49→      }
50→
51→      if (newTier !== card.tier) {
52→        await supabase.from('customer_cards').update({ tier: newTier }).eq('id', card.id);
53→
54→        // Send notification on tier change
55→        const token = (card as any).customers?.push_token;
56→        if (token) {
57→          const tierOrder = ['bronze', 'silver', 'gold', 'vip'];
58→          const isUpgrade = tierOrder.indexOf(newTier) > tierOrder.indexOf(card.tier ?? 'bronze');
59→          const title = isUpgrade
60→            ? `Congratulations! You're now ${newTier.toUpperCase()}!`
61→            : `Tier updated to ${newTier.toUpperCase()}`;
62→          const body = isUpgrade
63→            ? 'Keep it up to unlock more rewards!'
64→            : 'Keep visiting to maintain your tier!';
65→
66→          await fetch('https://exp.host/--/api/v2/push/send', {
67→            method: 'POST',
68→            headers: { 'Content-Type': 'application/json' },
69→            body: JSON.stringify({ to: token, title, body }),
70→          });
71→
72→          await supabase.from('notifications').insert({
73→            customer_id: card.customer_id,
74→            title,
75→            body,
76→            type: 'reward_available',
77→            sent_at: new Date().toISOString(),
78→          });
79→        }
80→        updated++;
81→      }
82→    }
83→
84→    return new Response(JSON.stringify({ updated }), {
85→      status: 200,
86→      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
87→    });
88→  } catch (err) {
89→    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
90→  }
91→});
