  4→  'Access-Control-Allow-Origin': '*',
  5→  'Access-Control-Allow-Headers':
  6→    'authorization, x-client-info, apikey, content-type',
  7→};
  8→
  9→Deno.serve(async (req) => {
 10→  if (req.method === 'OPTIONS') {
 11→    return new Response('ok', { headers: corsHeaders });
 12→  }
 13→
 14→  try {
 15→    const supabase = createClient(
 16→      Deno.env.get('SUPABASE_URL')!,
 17→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
 18→    );
 19→
 20→    const authHeader = req.headers.get('Authorization');
 21→    if (!authHeader) {
 22→      return new Response(JSON.stringify({ error: 'No auth' }), {
 23→        status: 401,
 24→        headers: corsHeaders,
 25→      });
 26→    }
 27→
 28→    const {
 29→      data: { user },
 30→      error: authError,
 31→    } = await supabase.auth.getUser(authHeader.replace('Bearer ', ''));
 32→    if (authError || !user) {
 33→      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
 34→        status: 401,
 35→        headers: corsHeaders,
 36→      });
 37→    }
 38→
 39→    const { qr_id, secret } = await req.json();
 40→
 41→    if (!qr_id || !secret) {
 42→      return new Response(
 43→        JSON.stringify({ error: 'Missing qr_id or secret' }),
 44→        { status: 400, headers: corsHeaders }
 45→      );
 46→    }
 47→
 48→    // Validate QR code
 49→    const { data: qrCode, error: qrError } = await supabase
 50→      .from('qr_codes')
 51→      .select('*, loyalty_programs(*)')
 52→      .eq('id', qr_id)
 53→      .eq('secret_key', secret)
 54→      .eq('is_active', true)
 55→      .single();
 56→
 57→    if (qrError || !qrCode) {
 58→      return new Response(JSON.stringify({ error: 'Invalid QR code' }), {
 59→        status: 400,
 60→        headers: corsHeaders,
 61→      });
 62→    }
 63→
 64→    const program = qrCode.loyalty_programs;
 65→
 66→    // Get or create customer card
 67→    let { data: card } = await supabase
 68→      .from('customer_cards')
 69→      .select('*')
 70→      .eq('customer_id', user.id)
 71→      .eq('program_id', program.id)
 72→      .single();
 73→
 74→    if (!card) {
 75→      // Ensure customer record exists
 76→      const { data: existingCustomer } = await supabase
 77→        .from('customers')
 78→        .select('id')
 79→        .eq('id', user.id)
 80→        .single();
 81→
 82→      if (!existingCustomer) {
 83→        await supabase
 84→          .from('customers')
 85→          .insert({ id: user.id, email: user.email! });
 86→      }
 87→
 88→      const { data: newCard } = await supabase
 89→        .from('customer_cards')
 90→        .insert({ customer_id: user.id, program_id: program.id })
 91→        .select()
 92→        .single();
 93→
 94→      card = newCard;
 95→    }
 96→
 97→    if (!card) {
 98→      return new Response(
 99→        JSON.stringify({ error: 'Could not create card' }),
100→        { status: 500, headers: corsHeaders }
101→      );
102→    }
103→
104→    // Add stamp or points
105→    let transactionType: string;
106→    let value: number;
107→
108→    if (program.type === 'stamp') {
109→      transactionType = 'stamp_add';
110→      value = 1;
111→
112→      await supabase
113→        .from('customer_cards')
114→        .update({
115→          current_stamps: card.current_stamps + 1,
116→          last_activity: new Date().toISOString(),
117→        })
118→        .eq('id', card.id);
119→    } else {
120→      transactionType = 'points_add';
121→      value = program.points_per_euro || 1;
122→
123→      await supabase
124→        .from('customer_cards')
125→        .update({
126→          current_points: card.current_points + value,
127→          last_activity: new Date().toISOString(),
128→        })
129→        .eq('id', card.id);
130→    }
131→
132→    // Record transaction
133→    await supabase.from('transactions').insert({
134→      card_id: card.id,
135→      type: transactionType,
136→      value,
137→      validated_by: 'qr',
138→    });
139→
140→    return new Response(
141→      JSON.stringify({
142→        success: true,
143→        program_name: program.name,
144→        type: program.type,
145→        added: value,
146→        new_total:
147→          program.type === 'stamp'
148→            ? card.current_stamps + 1
149→            : card.current_points + value,
150→        goal: program.type === 'stamp' ? program.stamp_goal : null,
151→      }),
152→      {
153→        status: 200,
154→        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
155→      }
156→    );
157→  } catch (err) {
158→    return new Response(JSON.stringify({ error: (err as Error).message }), {
159→      status: 500,
160→      headers: corsHeaders,
161→    });
162→  }
163→});
