163→            <Lock className="h-4 w-4" />
164→            <span>A/B Testing</span>
165→            <Link href="/subscription">
166→              <Badge variant="secondary" className="cursor-pointer hover:bg-gray-200">
167→                Business plan
168→              </Badge>
169→            </Link>
170→          </div>
171→        )}
172→      </div>
173→
174→      {abEnabled && canAbTest ? (
175→        <>
176→          <fieldset className="space-y-2 border rounded-md p-3">
177→            <legend className="px-1 text-sm font-medium text-indigo-700">
