179→            </legend>
180→            <div>
181→              <Label>Title (A)</Label>
182→              <Input
183→                value={title}
184→                onChange={(e) => setTitle(e.target.value)}
185→                placeholder="e.g. Weekend Special!"
186→                required
187→              />
188→            </div>
189→            <div>
190→              <Label>Message (A)</Label>
191→              <Textarea
192→                value={body}
193→                onChange={(e) => setBody(e.target.value)}
