  7→
  8→interface TierRule {
  9→  tier: string;
 10→  min_transactions: string;
 11→  min_points: string;
 12→}
 13→
 14→const TIERS = ['silver', 'gold', 'vip'] as const;
 15→
 16→const TIER_LABELS: Record<string, string> = {
 17→  silver: 'Silver',
 18→  gold: 'Gold',
 19→  vip: 'VIP',
 20→};
 21→
 22→const TIER_COLORS: Record<string, string> = {
 23→  silver: 'bg-gray-100 text-gray-700 border-gray-300',
 24→  gold: 'bg-yellow-50 text-yellow-800 border-yellow-300',
 25→  vip: 'bg-purple-50 text-purple-800 border-purple-300',
 26→};
 27→
 28→interface Props {
 29→  programId: string;
 30→}
 31→
 32→export function TierRulesForm({ programId }: Props) {
 33→  const supabase = createClient();
 34→  const [rules, setRules] = useState<TierRule[]>(
 35→    TIERS.map((tier) => ({ tier, min_transactions: '', min_points: '0' }))
 36→  );
 37→  const [loading, setLoading] = useState(false);
 38→  const [saved, setSaved] = useState(false);
 39→
 40→  useEffect(() => {
 41→    async function load() {
 42→      const { data } = await supabase
 43→        .from('tier_rules')
 44→        .select('*')
 45→        .eq('program_id', programId);
 46→
 47→      if (data && data.length > 0) {
 48→        setRules(
 49→          TIERS.map((tier) => {
 50→            const existing = data.find((r: any) => r.tier === tier);
 51→            return {
 52→              tier,
 53→              min_transactions: existing ? String(existing.min_transactions) : '',
 54→              min_points: existing ? String(existing.min_points ?? 0) : '0',
 55→            };
 56→          })
 57→        );
 58→      }
 59→    }
 60→    load();
 61→  }, [programId]);
 62→
 63→  async function handleSubmit(e: React.FormEvent) {
 64→    e.preventDefault();
 65→    setLoading(true);
 66→    setSaved(false);
 67→
 68→    // Delete existing rules for this program
 69→    await supabase.from('tier_rules').delete().eq('program_id', programId);
 70→
 71→    // Insert only tiers that have min_transactions defined
 72→    const toInsert = rules
 73→      .filter((r) => r.min_transactions !== '' && parseInt(r.min_transactions) > 0)
 74→      .map((r) => ({
 75→        program_id: programId,
 76→        tier: r.tier,
 77→        min_transactions: parseInt(r.min_transactions),
 78→        min_points: parseFloat(r.min_points) || 0,
 79→      }));
 80→
 81→    if (toInsert.length > 0) {
 82→      await supabase.from('tier_rules').insert(toInsert);
 83→    }
 84→
 85→    setLoading(false);
 86→    setSaved(true);
 87→    setTimeout(() => setSaved(false), 3000);
 88→  }
 89→
 90→  function updateRule(tier: string, field: 'min_transactions' | 'min_points', value: string) {
 91→    setRules((prev) =>
 92→      prev.map((r) => (r.tier === tier ? { ...r, [field]: value } : r))
 93→    );
 94→  }
 95→
 96→  return (
 97→    <form onSubmit={handleSubmit} className="space-y-4 max-w-lg mt-8">
 98→      <div>
 99→        <h3 className="text-lg font-semibold mb-1">Tier Rules</h3>
100→        <p className="text-sm text-gray-500 mb-4">
101→          Define the requirements for each loyalty tier. Customers are
102→          automatically promoted or demoted based on their activity in the last
103→          90 days. Leave a tier empty to disable it.
104→        </p>
105→      </div>
106→
107→      {TIERS.map((tier) => {
108→        const rule = rules.find((r) => r.tier === tier)!;
109→        return (
110→          <div
111→            key={tier}
112→            className={`p-4 border rounded-lg ${TIER_COLORS[tier]}`}
113→          >
114→            <Label className="text-sm font-bold mb-2 block">
115→              {TIER_LABELS[tier]} Tier
116→            </Label>
117→            <div className="grid grid-cols-2 gap-3">
118→              <div>
119→                <Label className="text-xs">Min. Transactions (90 days)</Label>
120→                <Input
121→                  type="number"
122→                  min="0"
123→                  value={rule.min_transactions}
124→                  onChange={(e) =>
125→                    updateRule(tier, 'min_transactions', e.target.value)
126→                  }
127→                  placeholder="e.g. 5"
128→                  className="bg-white"
129→                />
130→              </div>
131→              <div>
132→                <Label className="text-xs">Min. Points</Label>
133→                <Input
134→                  type="number"
135→                  min="0"
136→                  step="0.01"
137→                  value={rule.min_points}
138→                  onChange={(e) =>
139→                    updateRule(tier, 'min_points', e.target.value)
140→                  }
141→                  placeholder="0"
142→                  className="bg-white"
143→                />
144→              </div>
145→            </div>
146→          </div>
147→        );
148→      })}
149→
150→      <div className="flex items-center gap-3">
151→        <Button type="submit" disabled={loading}>
152→          {loading ? 'Saving...' : 'Save Tier Rules'}
153→        </Button>
154→        {saved && (
155→          <span className="text-sm text-green-600 font-medium">
156→            Tier rules saved!
157→          </span>
158→        )}
159→      </div>
160→    </form>
161→  );
162→}
