 1→import { NextRequest, NextResponse } from 'next/server';
 2→import { createClient } from '@supabase/supabase-js';
 3→
 4→// Public API endpoint for mobile app to track campaign events
 5→// POST /api/campaigns/track
 6→// Body: { campaign_id: string, event_type: 'open' | 'click' | 'conversion' }
 7→
 8→export async function POST(request: NextRequest) {
 9→  try {
10→    const { campaign_id, event_type } = await request.json();
11→
12→    if (!campaign_id || !event_type) {
13→      return NextResponse.json({ error: 'Missing campaign_id or event_type' }, { status: 400 });
14→    }
15→
16→    if (!['open', 'click', 'conversion'].includes(event_type)) {
17→      return NextResponse.json({ error: 'Invalid event_type' }, { status: 400 });
18→    }
19→
20→    const supabase = createClient(
21→      process.env.NEXT_PUBLIC_SUPABASE_URL!,
22→      process.env.SUPABASE_SERVICE_ROLE_KEY!,
23→    );
24→
25→    const { error } = await supabase.rpc('track_campaign_event', {
26→      p_campaign_id: campaign_id,
27→      p_event_type: event_type,
28→    });
29→
30→    if (error) {
31→      return NextResponse.json({ error: error.message }, { status: 500 });
32→    }
33→
34→    return NextResponse.json({ success: true });
35→  } catch {
36→    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
37→  }
38→}
